import { createSlice, nanoid } from "@reduxjs/toolkit";

const initialState = {
  items: [
    { id: "seed-1", name: "chicken breast", category: "protein", quantity: "2", unit: "pcs" },
    { id: "seed-2", name: "rice", category: "grain", quantity: "1", unit: "bag" },
    { id: "seed-3", name: "garlic", category: "produce", quantity: "4", unit: "cloves" },
  ],
};

const pantrySlice = createSlice({
  name: "pantry",
  initialState,
  reducers: {
    addPantryItem: {
      reducer(state, action) {
        const exists = state.items.some(
          (item) => item.name.toLowerCase() === action.payload.name.toLowerCase()
        );

        if (!exists) {
          state.items.push(action.payload);
        }
      },
      prepare(item) {
        return {
          payload: {
            id: nanoid(),
            name: item.name.trim(),
            category: item.category || "other",
            quantity: item.quantity || "",
            unit: item.unit || "",
          },
        };
      },
    },
    removePantryItem(state, action) {
      state.items = state.items.filter((item) => item.id !== action.payload);
    },
  },
});

export const { addPantryItem, removePantryItem } = pantrySlice.actions;
export default pantrySlice.reducer;
